#include <stdio.h>
#include <stdlib.h>
#include <sys/stat.h>

FILE *create_secure_temp() {
    char template[] = "/tmp/app_XXXXXX";
    int fd = mkstemp(template); // Compliant: secure temp file creation
    return fdopen(fd, "w");
}

// Or use user-specific directory:
FILE *create_user_temp() {
    char *home = getenv("HOME");
    char path[256];
    snprintf(path, sizeof(path), "%s/.myapp/temp.dat", home);
    mkdir(dirname(path), 0700); // Compliant: user-only access
    return fopen(path, "w");
}
